_cache = {}   # глобальный — живёт весь процесс

def handle(user_id, data):
    _cache[user_id] = data   # растёт бесконечно → утечка

class Positive:
    def __set_name__(self, owner, name):
        self.name = name
    def __set__(self, obj, value):
        if value < 0:
            raise ValueError('negative')
        obj.__dict__[self.name] = value

class Product:
    price = Positive()

class Meta(type):
    def __new__(mcs, name, bases, ns):
        print(f'creating class {name}')
        return super().__new__(mcs, name, bases, ns)

class Model(metaclass=Meta):   # печатает при объявлении
    pass

# math.pyx (Cython)
def fib(int n) -> int:
    cdef int a = 0, b = 1, i
    for i in range(n):
        a, b = b, a + b
    return a
